","import React from "react";

interface Segment {
 label: string;
 value: number;
}

interface DonutChartProps {
 data: Segment[];
 title: string;
 colors?: string[];
}

const DEFAULT_COLORS = [
 "#2E7D32", "#4CAF50", "#66BB6A", "#81C784", "#A5D6A7",
];

export default function DonutChart({
 data,
 title,
 colors = DEFAULT_COLORS,
}: DonutChartProps) {
 const total = data.reduce((s, d) => s + d.value, 0);
 if (total === 0) {
 return (
 <div className="cb-chart-card">
 <div className="cb-chart-title">{title}</div>
 <div className="cb-chart-empty">No data available</div>
 </div>
 );
 }

 const radius = 60;
 const cx = 80;
 const cy = 80;
 const circumference = 2 * Math.PI * radius;
 let offset = 0;

 return (
 <div className="cb-chart-card">
 <div className="cb-chart-title">{title}</div>
 <div className="cb-donut-wrapper">
 <svg viewBox="0 0 160 160" className="cb-donut-svg">
 {data.map((seg, i) => {
 const pct = seg.value / total;
 const dash = pct * circumference;
 const gap = circumference - dash;
 const currentOffset = offset;
 offset += dash;
 return (
 <circle
 key={seg.label}
 r={radius}
 cx={cx}
 cy={cy}
 fill="none"
 stroke={colors[i % colors.length]}
 strokeWidth="24"
 strokeDasharray={`${dash} ${gap}`}
 strokeDashoffset={-currentOffset}
 className="cb-donut-segment"
 />
 );
 })}
 <text x={cx} y={cy - 6} className="cb-donut-total">
 {total}
 </text>
 <text x={cx} y={cy + 12} className="cb-donut-label">
 Total
 </text>
 </svg>
 <div className="cb-donut-legend">
 {data.map((seg, i) => (
 <div key={seg.label} className="cb-legend-item">
 <span
 className="cb-legend-dot"
 style={{ backgroundColor: colors[i % colors.length] }}
 />
 <span className="cb-legend-text">
 {seg.label}: {seg.value}
 </span>
 </div>
 ))}
 </div>
 </div>
 </div>
 );
}
","import React from "react";

interface BarData {
 label: string;
 value: number;
}

interface BarChartProps {
 data: BarData[];
 title: string;
 colors?: string[];
}

const DEFAULT_COLORS = [
 "#2E7D32", "#4CAF50", "#66BB6A", "#81C784", "#A5D6A7",
];

export default function BarChart({
 data,
 title,
 colors = DEFAULT_COLORS,
}: BarChartProps) {
 const max = Math.max(...data.map((d) => d.value), 1);

 if (data.length === 0) {
 return (
 <div className="cb-chart-card">
 <div className="cb-chart-title">{title}</div>
 <div className="cb-chart-empty">No data available</div>
 </div>
 );
 }

 return (
 <div className="cb-chart-card">
 <div className="cb-chart-title">{title}</div>
 <div className="cb-bar-list">
 {data.map((bar, i) => (
 <div key={bar.label} className="cb-bar-row">
 <div className="cb-bar-label">{bar.label}</div>
 <div className="cb-bar-track">
 <div
 className="cb-bar-fill"
 style={{
 width: `${(bar.value / max) * 100}%`,
 backgroundColor: colors[i % colors.length],
 }}
 />
 </div>
 <div className="cb-bar-value">{bar.value}</div>
 </div>
 ))}
 </div>
 </div>
 );
}
","const HEADERS = {
 Accept: "application/json",
 "X-UserToken": (window as any).g_ck,
};

const TABLES = {
 returnRequest: "x_1845356_circle_0_return_request",
 deviceRecord: "x_1845356_circle_0_device_record",
 processingJob: "x_1845356_circle_0_processing_job",
 rewardFulfilment: "x_1845356_circle_0_reward_fulfilment",
};

async function statsQuery(table: string, params: string): Promise<any> {
 const res = await fetch(`/api/now/stats/${table}?${params}`, {
 headers: HEADERS,
 });
 return res.json();
}

export async function getTotalReturnRequests(): Promise<number> {
 const data = await statsQuery(
 TABLES.returnRequest,
 "sysparm_count=true"
 );
 return parseInt(data.result?.stats?.count || "0", 10);
}

export async function getReturnsByStatus(): Promise<
 { label: string; value: number }[]
> {
 const data = await statsQuery(
 TABLES.returnRequest,
 "sysparm_count=true&sysparm_group_by=status&sysparm_display_value=true"
 );
 return (data.result || []).map((g: any) => ({
 label: g.groupby_fields?.[0]?.display_value || g.groupby_fields?.[0]?.value || "Unknown",
 value: parseInt(g.stats?.count || "0", 10),
 }));
}

export async function getJobsByType(): Promise<
 { label: string; value: number }[]
> {
 const data = await statsQuery(
 TABLES.processingJob,
 "sysparm_count=true&sysparm_group_by=job_type&sysparm_display_value=true"
 );
 return (data.result || []).map((g: any) => ({
 label: g.groupby_fields?.[0]?.display_value || g.groupby_fields?.[0]?.value || "Unknown",
 value: parseInt(g.stats?.count || "0", 10),
 }));
}

export async function getRewardsIssued(): Promise<number> {
 const data = await statsQuery(
 TABLES.rewardFulfilment,
 "sysparm_count=true&sysparm_query=statusINissued,redeemed"
 );
 return parseInt(data.result?.stats?.count || "0", 10);
}

export async function getDevicesDiverted(): Promise<number> {
 const data = await statsQuery(
 TABLES.processingJob,
 "sysparm_count=true&sysparm_query=status=complete"
 );
 return parseInt(data.result?.stats?.count || "0", 10);
}

export async function getTotalWeightKg(): Promise<number> {
 const data = await statsQuery(
 TABLES.deviceRecord,
 "sysparm_sum_fields=weight_kg"
 );
 return parseFloat(data.result?.stats?.sum?.weight_kg || "0");
}

export async function getTotalMaterialsKg(): Promise<number> {
 const data = await statsQuery(
 TABLES.processingJob,
 "sysparm_sum_fields=materials_recovered_kg"
 );
 return parseFloat(
 data.result?.stats?.sum?.materials_recovered_kg || "0"
 );
}

export async function getDevicesByOutcome(): Promise<
 { label: string; value: number }[]
> {
 const data = await statsQuery(
 TABLES.processingJob,
 "sysparm_count=true&sysparm_group_by=job_type&sysparm_query=status=complete&sysparm_display_value=true"
 );
 return (data.result || []).map((g: any) => ({
 label: g.groupby_fields?.[0]?.display_value || g.groupby_fields?.[0]?.value || "Unknown",
 value: parseInt(g.stats?.count || "0", 10),
 }));
}
","/* ── CircleBack Programme Dashboard ── */

/* Reset */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

/* Container */
.cb-dash {
 max-width: 1200px;
 margin: 0 auto;
 padding: 24px 32px 48px;
 font-family: "Source Sans Pro", Arial, sans-serif;
 color: #212121;
}

/* Loading */
.cb-loading {
 text-align: center;
 padding: 80px 0;
 font-size: 16px;
 color: #666;
}

/* Header */
.cb-header {
 margin-bottom: 32px;
 border-bottom: 3px solid #2E7D32;
 padding-bottom: 16px;
}
.cb-title {
 font-size: 26px;
 font-weight: 700;
 color: #1B5E20;
 margin: 0;
}
.cb-subtitle {
 font-size: 14px;
 color: #555;
 margin-top: 4px;
}

/* Sections */
.cb-section {
 margin-bottom: 36px;
}
.cb-section + .cb-section {
 margin-top: 48px;
 padding-top: 32px;
 border-top: 3px solid #C8E6C9;
}
.cb-section-title {
 font-size: 20px;
 font-weight: 700;
 color: #1B5E20;
 margin: 0 0 16px;
 padding-bottom: 10px;
 border-bottom: 2px solid #C8E6C9;
}

/* KPI Grid */
.cb-kpi-grid {
 display: grid;
 grid-template-columns: repeat(2, 1fr);
 gap: 16px;
 margin-bottom: 20px;
}
.cb-kpi-grid--four {
 grid-template-columns: repeat(4, 1fr);
}

/* KPI Card */
.cb-kpi-card {
 background: linear-gradient(135deg, #E8F5E9 0%, #C8E6C9 100%);
 border-radius: 10px;
 padding: 20px 24px;
 border-left: 4px solid #2E7D32;
}
.cb-kpi-value {
 font-size: 32px;
 font-weight: 700;
 color: #1B5E20;
 line-height: 1.1;
}
.cb-kpi-unit {
 font-size: 16px;
 font-weight: 400;
 color: #388E3C;
 margin-left: 4px;
}
.cb-kpi-title {
 font-size: 13px;
 font-weight: 600;
 color: #4CAF50;
 margin-top: 6px;
 text-transform: uppercase;
 letter-spacing: 0.5px;
}

/* Chart Grid */
.cb-chart-grid {
 display: grid;
 grid-template-columns: repeat(2, 1fr);
 gap: 16px;
}

/* Chart Card */
.cb-chart-card {
 background: #FFFFFF;
 border-radius: 10px;
 padding: 20px 24px;
 border: 1px solid #C8E6C9;
}
.cb-chart-title {
 font-size: 15px;
 font-weight: 600;
 color: #2E7D32;
 margin-bottom: 16px;
}
.cb-chart-empty {
 text-align: center;
 padding: 40px 0;
 color: #999;
 font-size: 14px;
}

/* Donut Chart */
.cb-donut-wrapper {
 display: flex;
 align-items: center;
 gap: 24px;
}
.cb-donut-svg {
 width: 160px;
 height: 160px;
 flex-shrink: 0;
 transform: rotate(-90deg);
}
.cb-donut-segment {
 transition: stroke-dashoffset 0.6s ease;
}
.cb-donut-total {
 font-size: 22px;
 font-weight: 700;
 fill: #1B5E20;
 text-anchor: middle;
 dominant-baseline: middle;
 transform: rotate(90deg);
 transform-origin: center;
}
.cb-donut-label {
 font-size: 11px;
 fill: #666;
 text-anchor: middle;
 dominant-baseline: middle;
 transform: rotate(90deg);
 transform-origin: center;
}

/* Legend */
.cb-donut-legend {
 display: flex;
 flex-direction: column;
 gap: 6px;
}
.cb-legend-item {
 display: flex;
 align-items: center;
 gap: 8px;
}
.cb-legend-dot {
 width: 10px;
 height: 10px;
 border-radius: 50%;
 flex-shrink: 0;
}
.cb-legend-text {
 font-size: 13px;
 color: #333;
}

/* Bar Chart */
.cb-bar-list {
 display: flex;
 flex-direction: column;
 gap: 12px;
}
.cb-bar-row {
 display: flex;
 align-items: center;
 gap: 12px;
}
.cb-bar-label {
 width: 130px;
 font-size: 13px;
 font-weight: 500;
 color: #333;
 flex-shrink: 0;
 text-align: right;
}
.cb-bar-track {
 flex: 1;
 height: 24px;
 background: #E8F5E9;
 border-radius: 12px;
 overflow: hidden;
}
.cb-bar-fill {
 height: 100%;
 border-radius: 12px;
 transition: width 0.8s ease;
 min-width: 4px;
}
.cb-bar-value {
 width: 40px;
 font-size: 14px;
 font-weight: 700;
 color: #1B5E20;
 text-align: right;
}

/* Responsive */
@media (max-width: 900px) {
 .cb-kpi-grid--four { grid-template-columns: repeat(2, 1fr); }
 .cb-chart-grid { grid-template-columns: 1fr; }
}
","export default function insertStyle(css, tagName = "style") {
 if (!css || typeof window === "undefined")
 return;
 if (tagName === "style") {
 const style = document.createElement("style");
 style.setAttribute("type", "text/css");
 style.innerHTML = css;
 document.head.appendChild(style);
 }
 else if (tagName === "link") {
 const link = document.createElement("link");
 link.setAttribute("rel", "stylesheet");
 link.setAttribute("href", css);
 document.head.appendChild(link);
 }
 return css;
}","import React from "react";
