","import React, { useEffect, useState } from "react";
import KpiCard from "./components/KpiCard";
import DonutChart from "./components/DonutChart";
import BarChart from "./components/BarChart";
import {
 getTotalReturnRequests,
 getReturnsByStatus,
 getJobsByType,
 getRewardsIssued,
 getDevicesDiverted,
 getTotalWeightKg,
 getTotalMaterialsKg,
 getDevicesByOutcome,
} from "./services/api";
import "./dashboard.css";

interface DashState {
 totalReturns: number;
 returnsByStatus: { label: string; value: number }[];
 jobsByType: { label: string; value: number }[];
 rewardsIssued: number;
 devicesDiverted: number;
 totalWeightKg: number;
 totalMaterialsKg: number;
 devicesByOutcome: { label: string; value: number }[];
 loading: boolean;
}

export default function App() {
 const [state, setState] = useState<DashState>({
 totalReturns: 0,
 returnsByStatus: [],
 jobsByType: [],
 rewardsIssued: 0,
 devicesDiverted: 0,
 totalWeightKg: 0,
 totalMaterialsKg: 0,
 devicesByOutcome: [],
 loading: true,
 });

 useEffect(() => {
 Promise.all([
 getTotalReturnRequests(),
 getReturnsByStatus(),
 getJobsByType(),
 getRewardsIssued(),
 getDevicesDiverted(),
 getTotalWeightKg(),
 getTotalMaterialsKg(),
 getDevicesByOutcome(),
 ]).then(
 ([
 totalReturns, returnsByStatus, jobsByType, rewardsIssued,
 devicesDiverted, totalWeightKg, totalMaterialsKg, devicesByOutcome,
 ]) =>
 setState({
 totalReturns, returnsByStatus, jobsByType, rewardsIssued,
 devicesDiverted, totalWeightKg, totalMaterialsKg, devicesByOutcome,
 loading: false,
 })
 );
 }, []);

 if (state.loading) {
 return (
 <div className="cb-dash">
 <div className="cb-loading">Loading dashboard data…</div>
 </div>
 );
 }

 return (
 <div className="cb-dash">
 <header className="cb-header">
 <h1 className="cb-title">CircleBack Programme Dashboard</h1>
 <p className="cb-subtitle">
 Fairphone Consumer Electronics Take-Back Hub — Performance Overview
 </p>
 </header>

 <section className="cb-section">
 <h2 className="cb-section-title">Operational Metrics</h2>
 <div className="cb-kpi-grid">
 <KpiCard title="Total Return Requests" value={state.totalReturns} />
 <KpiCard title="Rewards Issued" value={state.rewardsIssued} />
 </div>
 <div className="cb-chart-grid">
 <DonutChart title="Returns by Status" data={state.returnsByStatus} />
 <BarChart title="Processing Jobs by Type" data={state.jobsByType} />
 </div>
 </section>

 <section className="cb-section">
 <h2 className="cb-section-title">ESG Impact</h2>
 <div className="cb-kpi-grid cb-kpi-grid--four">
 <KpiCard
 title="Devices Diverted from Landfill"
 value={state.devicesDiverted}
 />
 <KpiCard
 title="Total Weight Processed"
 value={state.totalWeightKg.toFixed(1)}
 unit="kg"
 />
 <KpiCard
 title="Total Materials Recovered"
 value={state.totalMaterialsKg.toFixed(1)}
 unit="kg"
 />
 <KpiCard title="Rewards Issued" value={state.rewardsIssued} />
 </div>
 <div className="cb-chart-grid">
 <BarChart
 title="Devices by Outcome"
 data={state.devicesByOutcome}
 />
 </div>
 </section>
 </div>
 );
}
